static void controller_set_holding(controller_t *controller)
{
    controller->state = CONTROLLER_STATE_HOLDING;
}

static bool controller_sensor_is_stale(const controller_t *controller, uint32_t now_ms)
{
    if (controller == 0) {
        return false;
    }

    if (!controller->has_valid_sensor) {
        return now_ms > CONTROLLER_SENSOR_TIMEOUT_MS;
    }

    return (uint32_t)(now_ms - controller->last_valid_sensor_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

